UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('split-squat-eccentric-to-pause', 'Supported split stance hold or shallow eccentric.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('isometric-lateral-lunge-hold', 'Shallow lateral shift hold.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('cossack-bottom-hold-cossack-shift-hold', 'Cossack shift only, no bottom hold.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('adductor-squeeze-bridge-hold', 'Supine adductor squeeze only, no bridge.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('hamstring-bridge-iso-long-lever-bridge-hold', 'Short-lever glute bridge hold.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('slider-hamstring-eccentric-slow-lower', 'Hamstring bridge ISO only.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('calf-isometric-hold-straight-knee', 'Double-leg calf hold with support.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('soleus-isometric-hold-bent-knee', 'Double-leg bent-knee calf hold with wall support.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('tibialis-iso-toe-up-hold', 'Seated toe-up hold or wall-supported toe raise.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('nordic-lean-isometric-partial-range', 'Do not use; use hamstring bridge ISO.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

INSERT INTO coaching.exercise_scaling_profile (exercise_id, cohort_key, label, scale_direction, load_guidance, gender_specific_notes)
SELECT e.id, 'youth_beginner', 'youth beginner', 'baseline', v.guidance,
  CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE NULL END
FROM (VALUES
  ('split-squat-eccentric-to-pause', 'Supported split stance hold or shallow eccentric.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('isometric-lateral-lunge-hold', 'Shallow lateral shift hold.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('cossack-bottom-hold-cossack-shift-hold', 'Cossack shift only, no bottom hold.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('adductor-squeeze-bridge-hold', 'Supine adductor squeeze only, no bridge.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('hamstring-bridge-iso-long-lever-bridge-hold', 'Short-lever glute bridge hold.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('slider-hamstring-eccentric-slow-lower', 'Hamstring bridge ISO only.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('calf-isometric-hold-straight-knee', 'Double-leg calf hold with support.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('soleus-isometric-hold-bent-knee', 'Double-leg bent-knee calf hold with wall support.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('tibialis-iso-toe-up-hold', 'Seated toe-up hold or wall-supported toe raise.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.'),
  ('nordic-lean-isometric-partial-range', 'Do not use; use hamstring bridge ISO.', 'No default sex-based adjustment. Scale by joint comfort, symptom tolerance, training age, and supervision needs rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE NOT EXISTS (
  SELECT 1 FROM coaching.exercise_scaling_profile sp
  WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner'
);

