INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops position ownership, alignment, and low-speed joint resilience for safer Output and Capacity.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('split-squat-eccentric-to-pause', 'Split squat eccentric-to-pause builds the ability to lower under control, pause without collapsing, and return with alignment — stance length, depth, and trunk angle are meaningful scaling variables.', 'Belongs in split_stance_eccentric_control (551) — knee/hip split-stance control before loaded lunges or dynamic decel.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Avoid passive bottom collapse; hypermobility athletes need active front foot and hip tension — do not hang into end range.'),
  ('isometric-lateral-lunge-hold', 'Isometric lateral lunge hold builds ownership of a side-loaded position before dynamic lateral lunging, Cossacks, skater bounds, or cutting.', 'Belongs in frontal_plane_isometric_control (552) — lateral position ownership before Cossack or loaded lateral work.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Avoid passive groin end range; hypermobility athletes need active mid-range holds — do not force depth.'),
  ('cossack-bottom-hold-cossack-shift-hold', 'Cossack bottom hold develops active strength and control in a deep side-loaded position — range must be earned rather than forced.', 'Belongs in deep_frontal_plane_control (553) — deep lateral ownership after lateral lunge hold.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Own active range only; hypermobility athletes must avoid passive end-range sinking.'),
  ('adductor-squeeze-bridge-hold', 'Adductor squeeze bridge combines a bridge pattern with isometric adductor squeeze — building knee and hip stability with low barrier to entry.', 'Belongs in adductor_isometric_control (554) — low-barrier groin/adductor control before Copenhagen or lateral loading.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Avoid over-squeezing into hip/knee discomfort; hypermobility athletes need controlled pelvis — do not arch at top.'),
  ('hamstring-bridge-iso-long-lever-bridge-hold', 'Hamstring bridge isometrics train posterior-chain position control in a lower-risk setup than Nordics or sliders — lever length controls difficulty.', 'Belongs in hamstring_bridge_control (555) — first hamstring ISO before slider eccentrics or Nordic progressions.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Shorten lever or move feet closer when cramping appears; hypermobility athletes need pelvis control — avoid lumbar extension at top.'),
  ('slider-hamstring-eccentric-slow-lower', 'Slider hamstring eccentrics train hamstrings to control knee extension while hips stay bridged — eccentric programs support hamstring injury resilience when dosed conservatively.', 'Belongs in hamstring_eccentric_control (556) — controlled eccentric after bridge ISO competency.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Shorten slide range and reset each rep when hips drop; hypermobility athletes need controlled range — avoid end-range strain.'),
  ('calf-isometric-hold-straight-knee', 'Straight-knee calf isometrics load the gastrocnemius-Achilles unit in a stable position — useful for tendon-friendly lower-leg resilience when symptoms are monitored.', 'Belongs in gastroc_isometric_control (557) — straight-knee calf/Achilles tolerance before elastic Output work.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Reduce hold height, load, or duration if Achilles pain worsens after session; hypermobility athletes need active ankle alignment.'),
  ('soleus-isometric-hold-bent-knee', 'Bent-knee calf work biases the soleus more than straight-knee work — supporting sport-relevant lower-leg tolerance when symptoms are monitored.', 'Belongs in soleus_isometric_control (558) — bent-knee complement to gastroc ISO before elastic lower-leg Output.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Use seated or supported setup when balance is limited; hypermobility athletes need ankle alignment — avoid knee collapse.'),
  ('tibialis-iso-toe-up-hold', 'Tibialis anterior drives dorsiflexion and foot control — toe-up holds build shin capacity and landing-prep lower-leg balance.', 'Belongs in tibialis_isometric_control (559) — dorsiflexor control complement to calf/soleus ISO work.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Reduce range or volume when anterior shin symptoms appear; hypermobility athletes need controlled active hold — avoid snapping into end range.'),
  ('nordic-lean-isometric-partial-range', 'Partial-range Nordic isometrics teach body-line and hamstring tension before full eccentric Nordics — high stress and should be progressed carefully.', 'Belongs in hamstring_isometric_resilience (560) — high-level hamstring tolerance after bridge and slider eccentric competency.', '', 'Joint resilience is slow position ownership — control the lowering, own the pause, monitor symptoms. Not Capacity max loading, Fitness burn circuits, or high-rep accessory fatigue work.', 'Keep range small and trunk active; hypermobility athletes need active hamstring tension — avoid lumbar extension.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
